import sys

class Solution:
    def subsets(self, nums: list[int]) -> list[list[int]]:
        res: list[list[int]] = []
        n = len(nums)
        # iterate over all masks
        for mask in range(1 << n):
            subset: list[int] = []
            for i in range(n):
                if mask & (1 << i):
                    subset.append(nums[i])
            res.append(subset)
        return res

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    # first line may be number of test cases, but according to format it's always 1
    try:
        _ = int(next(it))  # discard test case count
        n = int(next(it))
        nums = [int(next(it)) for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.subsets(nums)
    # output count then each subset on its own line
    print(len(ans))
    for subset in ans:
        if subset:
            print('[' + ' '.join(map(str, subset)) + ']')
        else:
            print('[]')

