#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> subsets(vector<int>& nums) {
        vector<vector<int>> res;
        int n = nums.size();
        for (int mask = 0; mask < (1 << n); ++mask) {
            vector<int> subset;
            for (int i = 0; i < n; ++i) {
                if (mask & (1 << i)) subset.push_back(nums[i]);
            }
            res.push_back(move(subset));
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    if (!(cin >> t)) return 0; // number of test cases, expected 1
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) cin >> nums[i];
    Solution sol;
    vector<vector<int>> ans = sol.subsets(nums);
    cout << ans.size() << "\n";
    for (const auto& subset : ans) {
        if (subset.empty()) {
            cout << "[]\n";
        } else {
            cout << "[";
            for (size_t i = 0; i < subset.size(); ++i) {
                if (i) cout << ' ';
                cout << subset[i];
            }
            cout << "]\n";
        }
    }
    return 0;
}
